function kBigIndices(nums, k) {
    const n = nums.length;
    const left = Array(n).fill(0);
    const right = Array(n).fill(0);

    for (let i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1])
            left[i] = left[i - 1] + 1;

        let j = n - 1 - i;
        if (nums[j] < nums[j + 1])
            right[j] = right[j + 1] + 1;
    }

    let count = 0;
    for (let i = 0; i < n; i++)
        if (left[i] >= k && right[i] >= k)
            count++;

    return count;
}
